mapper.insert:
/* wms-inventory-atmc-sql-oracle.xml - insertTworkInfoIvat - 재고 속성 등록  SQL */
	INSERT INTO TWORK_INFO_IVAT
		 (
		 CTKEY
		 , IVATKEY
		 , OWKEY
		 , ICKEY
		 , PRODUCTDATE
		 , EXPIREDATE
		 , ATTRIBUTE1
		 , ATTRIBUTE2
		 , ATTRIBUTE3
		 , ATTRIBUTE4
		 , ATTRIBUTE5
		 , PRODUCTLOT
		 , IVATSTATUS
		 , IBCONFIRMDATE
		 , LOGGRPCD
		 , ACKEY
		 , STORE_KEY
		 , ATTRIBUTE6
		 , ATTRIBUTE7
		 , ATTRIBUTE8
		 , ATTRIBUTE9
		 , IDNTFC_NO
		 , BDDR_GNRL_ITEM_IBYN
		 , CON_QTY
		 , NET_WGT
		 , CFQTY
		 , PLT_TYPE
		 , PLT_LOAD_QTY
		 , PLT_LOAD_HEIGHT
		 , UOM
		 , INSERTDATE
		 , INSERTURKEY
		 , UPDATEDATE
		 , UPDATEURKEY
		 ) VALUES 
		 (
		 #{ctkey}
		 , #{ivatkey}
		 , #{owkey}
		 , #{ickey}
		 , #{productdate}
		 , #{expiredate}
		 , '2'  /* DC */
		 , '1'  /* 일반 */
		 , #{attribute3}
		 , #{attribute4}
		 , #{attribute5}
		 , #{productlot}
		 , '10'
		 , COALESCE(#{ibconfirmdate}, TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS'))
		 , COALESCE(#{loggrpcd}, '1')
		 , #{ackey}
		 , #{storeKey}
		 , #{attribute6}
		 , #{attribute7}
		 , #{attribute8}
		 , #{attribute9}
		 , #{idntfcNo}
		 , #{bddrGnrlItemIbyn}
		 , #{conQty}
		 , #{netWgt}
		 , #{cfqty}
		 , #{pltType}
		 , #{pltLoadQty}
		 , #{pltLoadHeight}
		 , #{uom}
		 , TO_CHAR(CURRENT_TIMESTAMP , 'YYYYMMDDHH24MISS')
		 , #{surkey}
		 , TO_CHAR(CURRENT_TIMESTAMP , 'YYYYMMDDHH24MISS')
		 , #{surkey}
		 )

mapper.select:
	/* wms-inventory-atmc-sql-oracle.xml - selectIcutQty - 상품 입수수량 조회  SQL */
	    SELECT IC.CTKEY
	         , IC.OWKEY
	         , IC.ICUTKEY
	         , IT.ICUTTYPE
	         , IT.ICUTQTY
	      FROM TWORK_MST_IC IC
	           INNER JOIN
	           TWORK_MST_ICUTXTYPE IT
	             ON IC.CTKEY = IT.CTKEY
	            AND IC.OWKEY = IT.OWKEY
	            AND IC.ICUTKEY = IT.ICUTKEY
         WHERE IC.CTKEY = #{ctkey}
           AND IC.OWKEY = #{owkey}
           AND IC.ICKEY = #{ickey}
           AND IT.ICUTTYPE = #{uom}

mapper.update:
/* wms-inventory-atmc-sql-oracle.xml - updateInvnQty - 재고 수정  SQL */
	 UPDATE TWORK_INFO_IVATXLCXULC
	 	SET TTQTY = TTQTY + (#{normalqty} * #{icutqty}) + (#{hoqty} * #{icutqty})
	 	  , AVQTY = AVQTY + (#{normalqty} * #{icutqty})
	 	  , HOQTY = (#{hoqty} * #{icutqty})
	 	  , UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP , 'YYYYMMDDHH24MISS')
	 	  , UPDATEURKEY = #{surkey}
	  WHERE CTKEY = #{ctkey}
	    AND OWKEY = #{owkey}
	    AND ICKEY = #{ickey}
	    AND LCKEY = #{lckey}
	    AND IVATKEY = #{ivatkey}

/* wms-inventory-atmc-sql-oracle.xml - updateInvnQtyMinus - 재고 차감  SQL */
	 UPDATE TWORK_INFO_IVATXLCXULC
	 	SET TTQTY = TTQTY - (#{normalqty} * #{icutqty}) - (#{hoqty} * #{icutqty})
	 	  , AVQTY = AVQTY - (#{normalqty} * #{icutqty}) - (#{hoqty} * #{icutqty})
	 	  , UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP , 'YYYYMMDDHH24MISS')
	 	  , UPDATEURKEY = #{surkey}
	  WHERE CTKEY = #{ctkey}
	    AND OWKEY = #{owkey}
	    AND ICKEY = #{ickey}
	    AND LCKEY = #{fcLckey}
	    AND IVATKEY = #{ivatkey}
